  ('social-worker-moex-06610', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於「歸納法」的敘述，下列何者正確？', '["為了發展與證實或考驗普遍命題以及因果律而採取的質性程序", "從普遍性理論推論到特殊結論的邏輯模型", "資料的分析在於形式、主題與類別", "強調論證是否有效而非結論是否真確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
